# Lifting (x,y) to polynomial features
def phi(x, y, degree=5):
    features = []
    for i in range(degree + 1):
        for j in range(degree + 1 - i):
            features.append(x**i * y**j)
    return np.array(features)

# Now phi(1, 2) has 21 components for degree=5
# A 3×21 matrix W can approximate f by:
# f(x,y) ≈ W @ phi(x, y)
